{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleMultilineSuperTypeTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of indentation class body when class has multiline super type list.
 * These tests verify that the class body is NOT indented when the class has a multiline super type list.
 */
internal class IndentationRuleMultilineSuperTypeTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a class without explicit constructor but with multiline super type list - class body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor and multiline super type list - class body and super type continuation should not be indented`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor and multiline super type list - formats correctly`() {
        val code =
            """
            class Foo
            constructor(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a class with annotations before constructor and multiline super type list - class body should not be indented`() {
        val code =
            """
            class Foo
                @Bar1 @Bar2
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) : Foobar(
                    "foobar1",
                    "foobar2",
                ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with constructor without super type list - class body should not be indented`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with primary constructor and single line super type - class body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2) {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor and complex multiline super type list - class body should not be indented`() {
